  background: 'var(--ink3)',
  border: '1px solid var(--border)',
  color: 'var(--text)',
  padding: '8px 12px',
  fontSize: '0.83rem',
  borderRadius: 3,
  outline: 'none',
  cursor: 'pointer',
};
